use std::collections::BinaryHeap;
use std::cmp::Ordering;

#[derive(Copy, Clone, Eq, PartialEq)]
struct State {
    cost: i64,
    node: usize,
    used: bool,
}

impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        other.cost.cmp(&self.cost)
            .then_with(|| self.node.cmp(&other.node))
            .then_with(|| self.used.cmp(&other.used))
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

fn solve(n: i64, edges: Vec<Vec<i64>>) -> i64 {
    let n = n as usize;
    let mut graph: Vec<Vec<(usize, i64)>> = vec![vec![]; n];
    let mut rev_graph: Vec<Vec<(usize, i64)>> = vec![vec![]; n];

    for e in edges {
        let u = e[0] as usize;
        let v = e[1] as usize;
        let w = e[2] as i64;
        graph[u].push((v, w));
        rev_graph[v].push((u, w));
    }

    let mut dist0 = vec![i64::MAX; n];
    let mut dist1 = vec![i64::MAX; n];
    dist0[0] = 0;

    let mut heap = BinaryHeap::new();
    heap.push(State { cost: 0, node: 0, used: false });

    while let Some(State { cost, node, used }) = heap.pop() {
        if used && cost != dist1[node] {
            continue;
        }
        if !used && cost != dist0[node] {
            continue;
        }

        if !used {
            for &(next, w) in &graph[node] {
                let next_cost = cost + w;
                if next_cost < dist0[next] {
                    dist0[next] = next_cost;
                    heap.push(State { cost: next_cost, node: next, used: false });
                }
            }

            for &(prev, w) in &rev_graph[node] {
                let next_cost = cost + 2 * w;
                if next_cost < dist0[prev] {
                    dist0[prev] = next_cost;
                    heap.push(State { cost: next_cost, node: prev, used: false });
                }
            }
        }
        if used {
            for &(next, w) in &graph[node] {
                let next_cost = cost + w;
                if next_cost < dist0[next] {
                    dist0[next] = next_cost;
                    heap.push(State { cost: next_cost, node: next, used: false });
                }
            }
        }
    }

    let ans = std::cmp::min(dist0[n-1], dist1[n-1]);
    if ans == i64::MAX {
        -1
    } else {
        ans
    }
}
```

### Explanation
1. **Initialization**: We initialize two distance arrays, `dist0` and `dist1`, to store the minimum cost to reach each node in state 0 and state 1, respectively. Both arrays are initialized to a large value (infinity), except for the starting node (node 0 in state 0 with cost 0).
2. **Priority Queue**: We use a min-heap to prioritize processing nodes with the smallest current cost. Each entry in the heap is a `State` containing the current cost, node, and a boolean indicating if the node's switch was used.
3. **Processing States**:
   - **State 0 (Switch Not Used)**: For each outgoing edge, we update the neighbor's state 0 cost. For each incoming edge, we simulate reversing the edge (cost = `2 * w`) and update the predecessor's state 0 cost.
   - **State 1 (Switch Used)**: We only process outgoing edges to update neighbors' state 0 costs, as the switch can't be reused.
4. **Termination**: The minimum cost to reach node `n-1` is the minimum value between its state 0 and state 1 costs. If both remain infinity, return -1 indicating the node is unreachable.

This approach efficiently models the problem by leveraging Dijkstra's algorithm with a state per node, ensuring optimal path exploration while respecting the constraints of using each node's switch at most once.

