use std::collections::BinaryHeap;

fn solve(n: i64, edges: Vec<Vec<i64>>) -> i64 {
    let nn = n as usize;
    let mut g: Vec<Vec<(usize, i64)>> = vec![vec![]; nn];
    let mut rg: Vec<Vec<(usize, i64)>> = vec![vec![]; nn];

    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let w = edge[2];
        g[u].push((v, w));
        rg[v].push((u, w));
    }

    let inf: i64 = 1_i64 << 60;
    let mut dist0: Vec<i64> = vec![inf; nn];
    let mut dist1: Vec<i64> = vec![inf; nn];
    dist0[0] = 0;

    let mut heap: BinaryHeap<((i64, usize), usize)> = BinaryHeap::new();
    heap.push(((-0, 0), 0));

    while let Some(((neg_cost, u), state)) = heap.pop() {
        let cost = -neg_cost;
        if state == 0 {
            if cost != dist0[u] {
                continue;
            }
        } else if state == 1 {
            if cost != dist1[u] {
                continue;
            }
        }

        if state == 0 {
            for &(v, w) in &g[u] {
                let next_cost = cost + w;
                if next_cost < dist0[v] {
                    dist0[v] = next_cost;
                    heap.push(((-next_cost, v), 0));
                }
            }

            for &(v, w) in &rg[u] {
                let next_cost = cost + 2 * w;
                if next_cost < dist0[v] {
                    dist0[v] = next_cost;
                    heap.push(((-next_cost, v), 0));
                }
            }

            if cost < dist1[u] {
                dist1[u] = cost;
                heap.push(((-cost, u), 1));
            }
        } else {
            for &(v, w) in &g[u] {
                let next_cost = cost + w;
                if next_cost < dist0[v] {
                    dist0[v] = next_cost;
                    heap.push(((-next_cost, v), 0));
                }
            }
        }
    }

    let res = std::cmp::min(dist0[nn - 1], dist1[nn - 1]);
    if res >= inf {
        -1
    } else {
        res
    }
}
```

### Explanation
1. **Graph Construction**:
   - The graph `g` stores outgoing edges for each node.
   - The reverse graph `rg` stores incoming edges for each node, which are potential edges that can be reversed using the node's switch.

2. **Dijkstra's Algorithm**:
   - **Initialization**: Start from node 0 with cost 0 in state 0 (switch available). Push this initial state into the priority queue.
   - **Processing**:
     - **State 0 (switch available)**:
       - **Outgoing Edges**: Traverse normally, updating the cost to reach neighbor nodes in state 0.
       - **Reversed Edges**: Use the switch to reverse incoming edges, updating the cost to reach the source nodes of these edges in state 0.
       - **Mark State 1**: Push the current node into state 1 (switch used) with the same cost, allowing future paths to traverse outgoing edges without using the switch again.
     - **State 1 (switch used)**: Only traverse outgoing edges normally, updating costs for neighbor nodes in state 0.

3. **Result Extraction**:
   - The minimum cost to reach node \( n-1 \) is the minimum between `dist0[n-1]` and `dist1[n-1]`. If both remain at infinity (indicating no path exists), return -1.

This approach efficiently explores all possible paths while leveraging the switches optimally, ensuring the minimal cost path is found using Dijkstra's algorithm with state tracking.
